package net.evarius.terranexus.landlord;
import net.evarius.terranexus.identity.AuthorityState;import net.evarius.terranexus.item.ModItems;import net.fabricmc.fabric.api.event.player.AttackBlockCallback;import net.minecraft.server.network.ServerPlayerEntity;import net.minecraft.text.Text;import net.minecraft.util.ActionResult;import net.minecraft.util.Formatting;
public final class LandSurveyEvents {private LandSurveyEvents(){}public static void register(){AttackBlockCallback.EVENT.register((player,world,hand,pos,direction)->{if(player.getStackInHand(hand).isOf(ModItems.LAND_SURVEY_TOOL)){if(!world.isClient()&&player instanceof ServerPlayerEntity serverPlayer){if(!AuthorityState.maySurveyLand(serverPlayer)){serverPlayer.sendMessage(Text.literal("Keine Vermessungsberechtigung.").formatted(Formatting.RED),true);return ActionResult.FAIL;}LandSelectionState selections=LandSelectionState.get(serverPlayer.getServer());selections.undo(serverPlayer.getUuid());serverPlayer.sendMessage(Text.literal("Letzter Vermessungspunkt entfernt · verbleibend: "+selections.points(serverPlayer.getUuid()).size()).formatted(Formatting.YELLOW),true);LandVisuals.preview(serverPlayer,selections.points(serverPlayer.getUuid()));}return ActionResult.FAIL;}return ActionResult.PASS;});}}
